  if (containsAny(text, "assumption", "constraint", "dependency")) return "KEY ASSUMPTIONS";
  if (containsAny(text, "risk", "issue")) return "KEY RISKS";
  if (containsAny(text, "team", "role")) return "TEAM FOCUS";
